#include <iostream>
class Stack {
    int data[4]{};
    int size_{0};
public:
    void push(int v) { data[++size_] = v; }
    int top()  const { return data[size_]; }
    void pop()       { --size_; }
};
int main() {
    Stack s;
    s.push(1);
    s.push(2);
    std::cout << s.top() << "\n";
    s.pop();
    std::cout << s.top() << "\n";
}
